import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

function hasUsefulRules(result) {
  return (
    result &&
    typeof result === "object" &&
    typeof result.market === "string" &&
    typeof result.description === "string" &&
    result.rulesSummary &&
    typeof result.rulesSummary === "object"
  );
}

export async function main() {
  const requestedSlug = "will-trump-win-2024";

  const readBatch = await callMcpSkillsParallel({
    label: "polymarket-rules-probe",
    calls: [
      {
        key: "exactRules",
        toolId: TOOL_ID,
        toolName: "check_market_rules",
        args: { slug: requestedSlug },
      },
      {
        key: "topMarkets",
        toolId: TOOL_ID,
        toolName: "get_top_markets",
        args: {
          limit: 20,
          sortBy: "total_volume",
          category: "politics",
        },
      },
    ],
  });

  const exactEntry = readBatch.results.find((entry) => entry.key === "exactRules");
  const topMarketsEntry = readBatch.results.find((entry) => entry.key === "topMarkets");

  const exactRules =
    exactEntry && exactEntry.status === "fulfilled" ? exactEntry.value : null;
  const topMarkets =
    topMarketsEntry && topMarketsEntry.status === "fulfilled" ? topMarketsEntry.value : null;

  if (hasUsefulRules(exactRules)) {
    const gotchas = Array.isArray(exactRules.rulesSummary.potentialGotchas)
      ? exactRules.rulesSummary.potentialGotchas
      : [];

    return {
      source: {
        kind: "requested_slug",
        slug: requestedSlug,
      },
      market: exactRules.market,
      description: exactRules.description,
      resolvesYesIf: exactRules.rulesSummary.resolvesYesIf || null,
      resolvesNoIf: exactRules.rulesSummary.resolvesNoIf || null,
      potentialGotchas: gotchas,
      fetchedAt: exactRules.fetchedAt,
      attemptedBranches: ["check_market_rules(slug)"],
      parallelTelemetry: readBatch.summary,
    };
  }

  const candidates = Array.isArray(topMarkets?.markets) ? topMarkets.markets : [];
  const ranked = pickTopSemanticCandidates({
    target: "highest-volume active US politics market for fallback market-rule resolution",
    candidates,
    requiredTerms: ["politics"],
    avoidTerms: ["resolved", "closed"],
    limit: 1,
  });

  const shortlist = Array.isArray(ranked) ? ranked : [];
  const selected = shortlist[0] || null;

  if (!selected || !selected.conditionId) {
    return {
      requestedSlug,
      usedFallback: true,
      missingData: ["No deterministically selected active US politics market was available"],
      attemptedBranches: [
        "check_market_rules(slug)",
        "get_top_markets(category=politics, sortBy=total_volume)",
        "pickTopSemanticCandidates(target=highest-volume active US politics market)",
      ],
      stopReason: "No fallback market found",
      parallelTelemetry: readBatch.summary,
    };
  }

  const fallbackRules = await callMcpSkill({
    toolId: TOOL_ID,
    toolName: "check_market_rules",
    args: { conditionId: selected.conditionId },
  });

  if (!hasUsefulRules(fallbackRules)) {
    return {
      requestedSlug,
      usedFallback: true,
      selectedFallbackMarket: {
        title: selected.title,
        slug: selected.slug,
        conditionId: selected.conditionId,
        url: selected.url,
      },
      missingData: ["Fallback market rules could not be resolved"],
      attemptedBranches: [
        "check_market_rules(slug)",
        "get_top_markets(category=politics, sortBy=total_volume)",
        "pickTopSemanticCandidates(target=highest-volume active US politics market)",
        "check_market_rules(conditionId)",
      ],
      stopReason: "Fallback rules unavailable",
      parallelTelemetry: readBatch.summary,
    };
  }

  const gotchas = Array.isArray(fallbackRules.rulesSummary.potentialGotchas)
    ? fallbackRules.rulesSummary.potentialGotchas
    : [];

  return {
    source: {
      kind: "fallback_market",
      title: selected.title,
      slug: selected.slug,
      conditionId: selected.conditionId,
      url: selected.url,
    },
    market: fallbackRules.market,
    description: fallbackRules.description,
    resolvesYesIf: fallbackRules.rulesSummary.resolvesYesIf || null,
    resolvesNoIf: fallbackRules.rulesSummary.resolvesNoIf || null,
    potentialGotchas: gotchas,
    fetchedAt: fallbackRules.fetchedAt,
    attemptedBranches: [
      "check_market_rules(slug)",
      "get_top_markets(category=politics, sortBy=total_volume)",
      "pickTopSemanticCandidates(target=highest-volume active US politics market)",
      "check_market_rules(conditionId)",
    ],
    parallelTelemetry: readBatch.summary,
  };
}

