    slug: setup?.slug,
    url: setup?.url,
    score: setup?.score,
    currentPrice: setup?.currentPrice,
    signal: setup?.signal,
    checks: setup?.checks,
    whaleInsights: setup?.whaleInsights,
    risks: setup?.risks,
    entryPlan: setup?.entryPlan,
    conditionId: setup?.conditionId
  }));

  return {
    fetchedAt: result?.fetchedAt,
    workflowSummary: result?.workflowSummary,
    analysisNotes: Array.isArray(result?.analysisNotes) ? result.analysisNotes : [],
