export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "summarize_live_market_activity",
    args: {
      category: "crypto",
      endingWithinDays: 3,
      sortBy: "ending_soon",
      tradeLimit: 50
    }
  });

  const buyVolume = result?.tradesSummary?.buyVolume;
  const sellVolume = result?.tradesSummary?.sellVolume;

  let skew = "unknown";
  if (typeof buyVolume === "number" && typeof sellVolume === "number") {
    if (buyVolume > sellVolume) skew = "buyers";
    else if (sellVolume > buyVolume) skew = "sellers";
    else skew = "neutral";
  }

  return {
    selectedMarketTitle: result?.selectedMarket?.title,
    endDate: result?.selectedMarket?.endDate,
    openInterestValue: result?.openInterest?.value,
    buyVolume,
    sellVolume,
    activitySkew: skew,
    selectedMarketConditionId: result?.selectedMarket?.conditionId,
    fetchedAt: result?.fetchedAt
  };
}

